import{c as i,O as t,i as a,m as e}from"./chunks/framework.BWIk71Uc.js";const c=JSON.parse('{"title":"文章加密功能演示","description":"演示如何使用加密组件保护文章内容","frontmatter":{"title":"文章加密功能演示","description":"演示如何使用加密组件保护文章内容","date":"2025-06-01T00:00:00.000Z","tags":["加密","安全","VitePress"],"category":"tools","status":"reviewing","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"notes/tools/encrypt-demo.md","filePath":"notes/tools/encrypt-demo.md","lastUpdated":1780128182000}'),n={name:"notes/tools/encrypt-demo.md"};function l(h,s,d,r,p,o){return t(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1748736000000"},[...s[0]||(s[0]=[e(`<h1 id="文章加密功能演示" tabindex="-1">文章加密功能演示 <a class="header-anchor" href="#文章加密功能演示" aria-label="Permalink to “文章加密功能演示”">​</a></h1><p>本页面演示了 VitePress 文章加密功能的两种用法。</p><h2 id="方式一-部分加密-推荐" tabindex="-1">方式一：部分加密（推荐） <a class="header-anchor" href="#方式一-部分加密-推荐" aria-label="Permalink to “方式一：部分加密（推荐）”">​</a></h2><p>使用 <code>&lt;Encrypted&gt;</code> 组件可以加密文章中的<strong>部分内容</strong>，适合混合公开/私密内容的场景。</p><h3 id="示例-加密一段内容" tabindex="-1">示例：加密一段内容 <a class="header-anchor" href="#示例-加密一段内容" aria-label="Permalink to “示例：加密一段内容”">​</a></h3><p>下面是加密的内容，密码是 <code>demo123</code>：</p><div class="tip custom-block"><p class="custom-block-title">使用方法</p><ol><li>运行加密脚本生成密文：<code>node scripts/encrypt.mjs -p &quot;你的密码&quot; -t &quot;要加密的内容&quot;</code></li><li>将生成的密文粘贴到组件的 <code>content</code> 属性中</li><li>把密码告诉需要查看的人</li></ol></div><h3 id="如何生成加密内容" tabindex="-1">如何生成加密内容 <a class="header-anchor" href="#如何生成加密内容" aria-label="Permalink to “如何生成加密内容”">​</a></h3><p>在项目根目录运行：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 加密一段文本</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/encrypt.mjs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;你的密码&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;要加密的内容&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 加密一个文件</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/encrypt.mjs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;你的密码&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;./secret-content.html&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 交互模式（推荐）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/encrypt.mjs</span></span></code></pre></div><p>脚本会输出一个 Base64 编码的密文，直接粘贴到 <code>&lt;Encrypted&gt;</code> 组件的 <code>content</code> 属性中即可。</p><h3 id="组件属性" tabindex="-1">组件属性 <a class="header-anchor" href="#组件属性" aria-label="Permalink to “组件属性”">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>必填</th><th>说明</th></tr></thead><tbody><tr><td><code>content</code></td><td><code>string</code></td><td>是</td><td>AES-GCM 加密后的 Base64 密文</td></tr><tr><td><code>hint</code></td><td><code>string</code></td><td>否</td><td>显示在密码输入框上方的提示文字</td></tr></tbody></table><h2 id="方式二-全文加密" tabindex="-1">方式二：全文加密 <a class="header-anchor" href="#方式二-全文加密" aria-label="Permalink to “方式二：全文加密”">​</a></h2><p>通过在文章的 frontmatter 中添加 <code>encrypted: true</code> 标记，可以加密整篇文章。访客需要输入密码才能看到文章内容。</p><h3 id="如何设置全文加密" tabindex="-1">如何设置全文加密 <a class="header-anchor" href="#如何设置全文加密" aria-label="Permalink to “如何设置全文加密”">​</a></h3><p><strong>第一步：生成验证密文</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/encrypt.mjs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;你的密码&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verify</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;文章标题&quot;</span></span></code></pre></div><p><strong>第二步：修改文章的 frontmatter</strong></p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">我的私密文章</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">encrypted</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">encryptedVerify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;这里粘贴上一步生成的验证密文&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">hint</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">请联系作者获取密码</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><table tabindex="0"><thead><tr><th>frontmatter 字段</th><th>说明</th></tr></thead><tbody><tr><td><code>encrypted</code></td><td>设为 <code>true</code> 启用全文加密</td></tr><tr><td><code>encryptedVerify</code></td><td>验证密文，用于校验密码是否正确</td></tr><tr><td><code>hint</code></td><td>可选，显示在密码输入框下方的提示</td></tr></tbody></table><h2 id="安全说明" tabindex="-1">安全说明 <a class="header-anchor" href="#安全说明" aria-label="Permalink to “安全说明”">​</a></h2><ul><li><strong>加密算法</strong>：AES-256-GCM（业界标准对称加密）</li><li><strong>密钥派生</strong>：PBKDF2-SHA256，600,000 次迭代（符合 OWASP 2025 推荐，防暴力破解）</li><li><strong>密码不存储</strong>：密码仅在浏览器内存中用于解密，不会被保存到任何地方</li><li><strong>随机化</strong>：每次加密使用随机 salt 和 IV，即使相同内容相同密码，每次密文也不同</li><li><strong>会话缓存</strong>：全文加密页面在同一个浏览器标签页内解锁后无需重复输入密码</li></ul><div class="warning custom-block"><p class="custom-block-title">注意事项</p><ul><li>此方案是<strong>前端加密</strong>，密码提示等信息在页面源码中可见</li><li>对于高安全需求的场景，建议配合服务端鉴权使用</li><li>爬虫无法获取加密内容，因为内容以密文形式存在，需要密码才能解密</li></ul></div>`,24)])])}const g=i(n,[["render",l]]);export{c as __pageData,g as default};
